import java.util.*;

public class CollectionsDemo {
    public static void main(String[] args) {
        // ArrayList — resizable array
        List<String> names = new ArrayList<>();
        names.add("Alice");
        names.add("Bob");
        names.add("Charlie");
        names.add(1, "Diana");  // insert at index
        names.remove("Bob");    // remove by value
        System.out.println(names);  // [Alice, Diana, Charlie]

        // HashMap — key-value mapping
        Map<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 95);
        scores.put("Bob", 87);
        scores.put("Charlie", 92);
        scores.putIfAbsent("Alice", 100);  // won't overwrite

        // Iterate map
        for (Map.Entry<String, Integer> entry : scores.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }

        // Get with default
        int aliceScore = scores.getOrDefault("Unknown", 0);

        // HashSet — unique elements
        Set<String> unique = new HashSet<>(names);
        unique.add("Alice");  // duplicate, won't add
        System.out.println(unique.size());

        // TreeMap — sorted keys
        Map<String, Integer> sorted = new TreeMap<>(scores);
        System.out.println(sorted);  // keys in alphabetical order

        // Collections utility
        Collections.sort(names);  // in-place sort
        Collections.reverse(names);
        int idx = Collections.binarySearch(names, "Diana");

        // Immutable collections (Java 9+)
        List<String> immutable = List.of("a", "b", "c");
        Map<String, Integer> immutableMap = Map.of("x", 1, "y", 2);
        // immutable.add("d");  // UnsupportedOperationException

        // Queue and Deque
        Queue<String> queue = new LinkedList<>();
        queue.offer("first");
        queue.offer("second");
        String polled = queue.poll();  // "first"

        Deque<String> stack = new ArrayDeque<>();
        stack.push("bottom");
        stack.push("top");
        String popped = stack.pop();  // "top"
    }
}
