// Custom exceptions
class InsufficientFundsException extends Exception {
    private final double deficit;

    public InsufficientFundsException(double deficit) {
        super("Insufficient funds. Need " + String.format("$%.2f", deficit) + " more.");
        this.deficit = deficit;
    }

    public double getDeficit() { return deficit; }
}

class AccountNotFoundException extends RuntimeException {
    public AccountNotFoundException(String id) {
        super("Account " + id + " not found.");
    }
}

class BankAccount {
    private final String id;
    private double balance;

    public BankAccount(String id, double balance) {
        this.id = id;
        this.balance = balance;
    }

    // Checked exception — caller must handle
    public void withdraw(double amount) throws InsufficientFundsException {
        if (amount > balance) {
            throw new InsufficientFundsException(amount - balance);
        }
        balance -= amount;
    }

    public double getBalance() { return balance; }
}

public class ExceptionDemo {
    public static void main(String[] args) {
        // Try-with-resources
        try (BufferedReader reader = new BufferedReader(
                new FileReader("data.txt"))) {
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + e.getMessage());
        } catch (IOException e) {
            System.err.println("Read error: " + e.getMessage());
        }

        // Checked exception handling
        BankAccount account = new BankAccount("ACC001", 100.0);
        try {
            account.withdraw(150.0);
        } catch (InsufficientFundsException e) {
            System.err.println(e.getMessage());
            System.err.printf("You need $%.2f more.%n", e.getDeficit());
        } finally {
            System.out.println("Transaction complete.");
        }

        // Multi-catch (Java 7+)
        try {
            riskyOperation();
        } catch (IOException | IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    static void riskyOperation() throws IOException {
        throw new IOException("Something went wrong");
