import java.util.*;
import java.util.stream.*;

public class StreamsDemo {
    record Student(String name, int age, String department, double gpa) {}

    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Alice", 22, "CS", 3.8),
            new Student("Bob", 20, "CS", 3.2),
            new Student("Charlie", 21, "Math", 3.5),
            new Student("Diana", 23, "CS", 3.9),
            new Student("Eve", 22, "Math", 2.8),
            new Student("Frank", 20, "Physics", 3.6)
        );

        // Filter, sort, collect
        List<String> csHonors = students.stream()
            .filter(s -> s.department().equals("CS"))
            .filter(s -> s.gpa() >= 3.5)
            .sorted(Comparator.comparing(Student::gpa).reversed())
            .map(Student::name)
            .collect(Collectors.toList());
        System.out.println("CS Honors: " + csHonors);

        // Grouping
        Map<String, List<Student>> byDept = students.stream()
            .collect(Collectors.groupingBy(Student::department));

        // Grouping with aggregation
        Map<String, Double> avgGpaByDept = students.stream()
            .collect(Collectors.groupingBy(
                Student::department,
                Collectors.averagingDouble(Student::gpa)
            ));
        System.out.println("Avg GPA by dept: " + avgGpaByDept);

        // Reduce — sum of all GPAs
        double totalGpa = students.stream()
            .mapToDouble(Student::gpa)
            .sum();

        // Statistics
        DoubleSummaryStatistics stats = students.stream()
            .mapToDouble(Student::gpa)
            .summaryStatistics();
        System.out.printf("GPA: min=%.1f, max=%.1f, avg=%.2f%n",
            stats.getMin(), stats.getMax(), stats.getAverage());

        // FlatMap — flatten nested collections
        List<List<Integer>> nested = List.of(
            List.of(1, 2, 3), List.of(4, 5), List.of(6, 7, 8, 9)
        );
        List<Integer> flat = nested.stream()
            .flatMap(Collection::stream)
            .collect(Collectors.toList());
        System.out.println("Flat: " + flat);

        // Parallel stream
        long count = students.parallelStream()
            .filter(s -> s.gpa() > 3.0)
            .count();
        System.out.println("Students with GPA > 3.0: " + count);
    }
}
