import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.*;

public class ConcurrencyDemo {
    private static int unsafeCounter = 0;
    private static final AtomicInteger safeCounter = new AtomicInteger(0);

    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(4);

        // Submit tasks and collect results
        List<Future<String>> futures = new ArrayList<>();
        for (int i = 0; i < 8; i++) {
            final int taskId = i;
            futures.add(pool.submit(() -> {
                Thread.sleep(100);
                return "Task " + taskId + " on " + Thread.currentThread().getName();
            }));
        }
        for (Future<String> f : futures) {
            System.out.println(f.get());
        }

        // Race condition demo
        ExecutorService racePool = Executors.newFixedThreadPool(10);
        List<Future<?>> tasks = new ArrayList<>();
        for (int i = 0; i < 1000; i++) {
            tasks.add(racePool.submit(() -> {
                unsafeCounter++;
                safeCounter.incrementAndGet();
            }));
        }
        for (Future<?> f : tasks) f.get();
        System.out.println("Unsafe: " + unsafeCounter);
        System.out.println("Safe: " + safeCounter.get());

        // CompletableFuture pipeline
        CompletableFuture<String> future = CompletableFuture
            .supplyAsync(() -> "Hello")
            .thenApplyAsync(g -> g + " World")
            .thenApplyAsync(msg -> msg + "!");
        System.out.println("Async: " + future.get());

        // Shutdown
        pool.shutdown();
        racePool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);
    }
}
